declare function watchDirectory(path: string): AsyncIterable<{ file: string; type: 'add' | 'change' | 'delete' }>;
declare function renderMarkdown(content: string): Promise<string>;
declare function deployToBucket(path: string, content: string): Promise<void>;

async function main() {
  const directoryPath = './docs';
  const bucketPath = 's3://my-static-bucket';

  for await (const event of watchDirectory(directoryPath)) {
    if (event.type === 'change' || event.type === 'add') {
      try {
        const content = await readFile(event.file);
        const html = await renderMarkdown(content);
        const outputPath = `${bucketPath}/${event.file.replace('.md', '.html')}`;

        await deployToBucket(outputPath, html);
        await logToAudit({ event: 'deploy', file: event.file, status: 'success' });
      } catch (error) {
        await logToAudit({ event: 'deploy', file: event.file, status: 'error', error });
        await sendSlackMessage('#alerts', `Deployment failed for ${event.file}`);
      }
    }
  }
}
