async function checkIpGeolocation(ip: string): Promise<number> {
  const data = await fetchFromApi(`https://geo-service.internal/ip/${ip}`);
  return data.riskScore ?? 0;
}

async function checkVelocityHistory(cardId: string): Promise<number> {
  const txs = await queryDatabase(
    `SELECT count(*) as count FROM transactions WHERE cardId = '${cardId}' AND created_at > NOW() - INTERVAL '1 hour'`
  );
  const count = txs[0]?.count ?? 0;
  return count > 5 ? 30 : count > 2 ? 10 : 0;
}

async function checkMerchantRisk(merchantId: string): Promise<number> {
  const merchant = await queryDatabase(
    `SELECT risk_level FROM merchants WHERE id = '${merchantId}'`
  );
  return merchant[0]?.risk_level ?? 0;
}

function calculateRiskScore(signals: RiskSignals): number {
  return signals.geoScore + signals.velocityScore + signals.merchantScore;
}

async function evaluateTransaction(transaction: Transaction): Promise<{ transactionId: string; riskScore: number }> {
  const [geoScore, velocityScore, merchantScore] = await Promise.all([
    checkIpGeolocation(transaction.ip),
    checkVelocityHistory(transaction.cardId),
    checkMerchantRisk(transaction.merchantId)
  ]);

  const score = calculateRiskScore({
    geoScore,
    velocityScore,
    merchantScore
  });

  return {
    transactionId: transaction.id,
    riskScore: score
  };
