async function main() {
  const queueUrl = 'https://queue.example.com/messages';
  const messages = pollSource(queueUrl, 5000);

  for await (const message of messages) {
    await processWithRetry(message);
  }
}

async function processWithRetry(message: any) {
  const maxRetries = 2;
  let lastError: Error | null = null;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      await processMessage(message);
      return;
    } catch (error) {
      lastError = error as Error;
      if (attempt < maxRetries) {
        await new Promise(resolve => setTimeout(resolve, 1000));
      }
    }
  }

  await moveToDeadLetterQueue(message, lastError);
  await sendOpsAlert(message, lastError);
}

async function processMessage(message: any) {
  await fetchFromApi('https://worker.internal/process', {
    method: 'POST',
    body: JSON.stringify(message)
  });
}

async function moveToDeadLetterQueue(message: any, error: Error) {
  await writeToDatabase('dead_letter_queue', {
    originalMessage: message,
    errorMessage: error.message,
    timestamp: new Date().toISOString()
  });
}

async function sendOpsAlert(message: any, error: Error) {
  const alertMessage = `Job failed for message ${message.id || 'unknown'}: ${error.message}`;
  await sendSlackMessage('ops-channel', alertMessage);
}
