async function main() {
  const stream = pollSource('https://metrics.internal/stream', 1000);
  let errorCount = 0;
  let totalCount = 0;
  let isAlerting = false;

  for await (const metric of stream) {
    totalCount++;
    if (metric.error) {
      errorCount++;
    }

    const errorRate = totalCount > 0 ? errorCount / totalCount : 0;

    if (errorRate > 0.05 && !isAlerting) {
      isAlerting = true;
      await Promise.allSettled([
        sendPagerDuty(`PagerDuty Alert: Error rate at ${(errorRate * 100).toFixed(2)}%`),
        logAudit({ event: 'HIGH_ERROR_RATE', rate: errorRate, timestamp: new Date() }),
        updateDashboard({ status: 'critical', errorRate, timestamp: new Date() })
      ]);
    }

    if (errorRate < 0.05 && isAlerting) {
      isAlerting = false;
    }
  }
}

function sendPagerDuty(message: string): Promise<void> {
  return sendPushNotification(message);
}

function logAudit(entry: any): Promise<void> {
  return logToAudit(entry);
}

function updateDashboard(data: any): Promise<void> {
  return writeToDatabase('status_dashboard', data);
}
