function validateEmail(email: string): boolean {
  const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return regex.test(email);
}

async function handleUserSignup(user: { email: string; name: string }): Promise<void> {
  if (!validateEmail(user.email)) {
    await logToAudit({ event: 'signup_validation_failed', email: user.email });
    return;
  }

  const verificationLink = `https://app.example.com/verify?token=${Date.now()}`;

  try {
    await writeToDatabase('users', { ...user, createdAt: new Date() });
  } catch (error) {
    await logToAudit({ event: 'signup_step_failed', step: 'create_user', error, user });
  }

  try {
    await sendEmail(user.email, 'Welcome to the Platform', `Hi ${user.name}, verify your account: ${verificationLink}`);
  } catch (error) {
    await logToAudit({ event: 'signup_step_failed', step: 'send_welcome_email', error, user });
  }

  try {
    await writeToDatabase('analytics_events', { event: 'user_signed_up', userId: user.email, timestamp: new Date() });
  } catch (error) {
    await logToAudit({ event: 'signup_step_failed', step: 'enqueue_analytics', error, user });
  }

  try {
    await writeToDatabase('workspaces', { ownerId: user.email, name: `${user.name}'s Workspace`, status: 'active' });
  } catch (error) {
    await logToAudit({ event: 'signup_step_failed', step: 'provision_workspace', error, user });
  }
}
